// Авто-подключение EV_ZT2_DATA к VWU
(function(){
  if(typeof VWU==='undefined') return;
  const ev=VWU.levels.find(l=>l.id==='ev');
  if(!ev) return;
  const zt2=ev.tests.find(t=>t.id==='ev_zt2');
  if(!zt2) return;
  delete zt2.empty;
  const gramRules=['vwu_konnektoren','satz_obwohl','satz_damit','reflexive','satz_praeteritum','prepositions',''];
  zt2.sections=[];
  EV_ZT2_DATA.grammatik.forEach((g,i)=>{
    const rk=gramRules[i]||'';
    zt2.sections.push({type:'lueckentext',name:g.name,desc:g.desc,bankLabel:g.bankLabel,perItem:g.perItem||0.5,items:g.items,ruleKey:rk||undefined});
  });
  EV_ZT2_DATA.wortschatz.forEach(w=>{
    zt2.sections.push({type:'lueckentext',name:w.name,desc:w.desc,perItem:w.perItem||0.5,items:w.items});
  });
})();
